DELETE FROM dish_ingredient WHERE dish_id IN (SELECT id FROM dish WHERE name IN ('红烧肉','宫保鸡丁','麻婆豆腐','糖醋排骨','可乐鸡翅','鱼香肉丝','清蒸鲈鱼','西红柿鸡蛋汤','紫菜蛋花汤','虎皮青椒'));
