DELETE FROM ingredient           WHERE name IN ('五花肉','排骨','鸡翅','花生','鲈鱼','茄子','紫菜(干)','木耳(干)','豆腐(嫩)','大葱','生姜','大蒜','酱油(生抽)','酱油(老抽)','醋','料酒','豆瓣酱','淀粉','冰糖','蚝油','可乐');

